parameters.text:
=You are an email assistant. Your job is TWO parts:

**PART 1 - SUMMARIZE:**
Read the following email body and create a clean 5-point bullet summary:

Email Subject: {{ $json.body.subject }}
Email Body: {{ $json.body.htmlBody }}

**PART 2 - OUTPUT FORMAT:**
Return a JSON object ONLY with this exact structure (no extra text):
{
  "summary": "<ul><li>Point 1</li><li>Point 2</li><li>Point 3</li><li>Point 4</li><li>Point 5</li></ul>",
  "toEmail": "{{ $json.body.toEmail }}",
  "subject": "{{ $json.body.subject }}",
  "originalBody": "{{ $json.body.htmlBody }}"
}

parameters.jsCode:
const raw = $input.first().json.output || $input.first().json.text || '';
let parsed;
try {
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = {
    summary: '<ul><li>Could not parse summary</li></ul>',
    toEmail: $input.first().json.toEmail || '',
    subject: $input.first().json.subject || '',
    originalBody: $input.first().json.originalBody || ''
  };
}
return [{ json: parsed }];

// Gmail node returns threadId after sending
// Save it to static workflow memory so we can check the exact thread later
const staticData = $getWorkflowStaticData('global');

const threadId = $input.first().json.threadId;
const messageId = $input.first().json.id;
const toEmail = $('Parse Agent JSON1').item.json.toEmail;
const subject = $('Parse Agent JSON1').item.json.subject;
const originalBody = $('Parse Agent JSON1').item.json.originalBody;

// Store in static memory
staticData['lastThread'] = {
  threadId: threadId,
  messageId: messageId,
  toEmail: toEmail,
  subject: subject,
  originalBody: originalBody,
  sentAt: new Date().toISOString()
};

console.log('✅ Saved threadId:', threadId);

return [{ json: { threadId, messageId, toEmail, subject, originalBody } }];

// Check if this incoming email belongs to a thread we're tracking
const staticData = $getWorkflowStaticData('global');
const incomingThreadId = $input.first().json.threadId;

console.log('📨 Incoming email threadId:', incomingThreadId);
console.log('📦 Tracked threads:', staticData.threads ? Object.keys(staticData.threads) : 'none');

if (!staticData.threads || !staticData.threads[incomingThreadId]) {
  // Not our thread - ignore
  return [{ json: { isTracked: false, threadId: incomingThreadId } }];
}

const threadData = staticData.threads[incomingThreadId];
const replyBody = $input.first().json.text || $input.first().json.snippet || '';
const fromEmail = $input.first().json.from || '';

return [{ json: {
  isTracked: true,
  threadId: incomingThreadId,
  replyBody,
  fromEmail,
  originalSubject: threadData.subject,
  originalBody: threadData.originalBody,
  toEmail: threadData.toEmail
}}];

parameters.text:
=You are a smart email assistant that replies to incoming emails.

Context - Original email we sent:
Subject: {{ $json.originalSubject }}
Body: {{ $json.originalBody }}

Their Reply:
{{ $json.replyBody }}

Write a helpful, professional reply to their message. Keep it concise and on-topic.

Return ONLY a JSON object:
{
  "subject": "Re: {{ $json.originalSubject }}",
  "body": "<the reply email in HTML format>"
}

parameters.jsCode:
const raw = $input.first().json.output || $input.first().json.text || '';
let parsed;
try {
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = {
    subject: 'Re: ' + ($('Is This Our Thread?').item.json.originalSubject || 'Your email'),
    body: '<p>Thank you for your reply! We will get back to you shortly.</p>'
  };
}
return [{ json: {
  ...parsed,
  toEmail: $('Is This Our Thread?').item.json.fromEmail,
  threadId: $('Is This Our Thread?').item.json.threadId
}}];

